const Q_PHYSICS_2018_MODEL_II=[{"id": "objective>Physics>2018 Model II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above illustrates a micrometer screw gauge. Determine its reading </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.44mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.46mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.86mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.96mm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram in the question is that of a micrometer screw gauge. <br/> Recall: To take the readings of a micrometer screw gauge, we take the sum of the main scale reading and the micro scale reading. <br/> Micrometer Reading = Mainscale reading + Microscale reading <br/> MR = MSR + msr ------ (1) <br/> MR = 2.00m + 0.46mm <br/>  = 2.46mm</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2018 Model II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If two bodies of different masses initially at rest are acted upon by the same force for the same time, then the two bodies acquire the same </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kinetic energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">momentum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">velocity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acceleration</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Force × time = Impulse = change in momentum <br/> Since the force and time are constant, the two bodies will acquire the same impulse, i.e the same change in momentum.</div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2018 Model II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> A force is applied at the end Q to a bar PQ pivoted at P (see diagram). The torque produced by the force F about the pivot is greatest when θ is  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">45°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">90°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">180°</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If L = length of PQ <br/> Torque about P = L(Fsinθ) = FLsinθ <br/> This is maximum when sinθ = 1, or θ = 90°</div>", "topic": "EQUILIBRIUM OF FORCES"}, {"id": "objective>Physics>2018 Model II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following graphs correctly represents the relationship between the kinetic energy (K.E) and the displacement (d) from point of release of a swinging pendulum bob?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For a swinging pendulum, at the point of rest, i.e at equilibruim, the K.E is maximum, when displaced so that it moves through a certain height h, the K.E decreases to minimum and then back to maximum as it comes back to the equilibrium position. <br/>  <br/>  <br/> The system contains both K.E and P.E at any instant in the motion. At the extreme positions, the P.E is equal to MGH. At B,  P.E=0, and K.E is maximum, K.E = 1/2 mv^2 <br/>  <br/> At the initial position, the K.E is zero, but as the acceleration of the pendulum Bob increases , the K.E increases and the reaches maximum at maximum displacement. Then when the pendulum Bob begins to decelerate, the K.E reduces till it becomes zero after deceleration <br/> </div>", "topic": "MOTION: SIMPLE HARMONIC MOTION (S.H.M)"}, {"id": "objective>Physics>2018 Model II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A rainbow is viewed through a blue sheet of glass. The rainbow will appear</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">white</div>", "<div style=\"font-family:Cambria;font-size:17px;\">yellow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">black</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a rainbow is viewed through a blue sheet of glass, the rainbow will appear blue. This is because the blue glass only allows blue light to pass through, absorbing all other colors. Therefore, the rainbow, which is made up of multiple colors, will appear blue when viewed through the blue glass.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS"}, {"id": "objective>Physics>2018 Model II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A ship traveling towards a cliff emits a whistle and receives the echo 3.5 seconds later. A short while later, the ship emits another whistle and receives the echo after 2.5 seconds. If the speed of sound in air is 250 m/s, how much closer has the ship moved to the cliff between the two whistle emissions?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">125m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">162N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">121N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">81N</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Speed of sound, v = 250 m/s <br/>  <br/> Time for first echo, t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 3.5 s <br/>  <br/> Time for second echo, t<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 2.5 s <br/>  <br/> The total distance the sound travels to the cliff and back is twice the distance from the ship to the cliff. Therefore, the distance to the cliff for each echo can be calculated using the formula: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">d</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v × t<hr size=\"1\" />2</td></tr></table></div> <br/> For the first echo: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">250 × 3.5<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">875<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">437.5</td><td style=\"text-align:center;\">m</td></tr></table></div> <br/> For the second echo: <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">250 × 2.5<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">625<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">312.5</td><td style=\"text-align:center;\">m</td></tr></table></div> <br/> Subtract the second distance from the first distance to find how much closer the ship is to the cliff: <br/>  <br/> Δd = d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> − d<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 437.5 m − 312.5 m = 125 m <br/>  <br/> The ship is 125 meters closer to the cliff.</div>", "topic": "PROPAGATION OF SOUND WAVES : ECHO AND REVERBERATION"}, {"id": "objective>Physics>2018 Model II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body is whirled round a circular path at constant speed. Which of the following diagrams correctly indicates the direction of the body's velocity (v) and acceleration (a)?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For a body undergoing circular motion, the acceleration is directed towards the centre, and the velocity is directed round the circumference of the circle as we have as below. <br/> <img src=\"2018 Model II/4v1ewr.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2018 Model II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A rectangular metal block of volume 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at 273k is heated to 573K. If its co-efficient of linear expansivity is 1.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>. The percentage of change of its volume is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.1%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.1%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4%</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>m<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 273K <br/> θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 573K <br/> α = 1.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Δθ = θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 300k <br/> % change in volume = unknown <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">N.B:</td><td style=\"text-align:center;\">γ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>Δθ</td><td style=\"text-align:center;\">------</td><td style=\"text-align:center;\">*</td></tr></table></div> <br/> γ = 3α ------ ** <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">%</td><td style=\"text-align:center;\">change</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">volume</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/> y = 3 × 1.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> = 3.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">3.6</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> × 300</td></tr></table></div> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 300 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> × 3.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 1.080 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-91</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 1.080 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-8</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">To</td><td style=\"text-align:center;\">change</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">volume</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.080×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span><hr size=\"1\" />10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100</td></tr></table></div> <br/>  = 1.080 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> × 100 <br/>  = 1.080% <br/>  ≈ 1.1%</div>", "topic": "THERMAL EXPANSION : SOLIDS"}, {"id": "objective>Physics>2018 Model II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The formular for maximum power transfer of a cell whose e.m.f is E and internal resistance r is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/r</div>", "<div style=\"font-family:Cambria;font-size:17px;\">E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/2r</div>", "<div style=\"font-family:Cambria;font-size:17px;\">E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/4r</div>", "<div style=\"font-family:Cambria;font-size:17px;\">E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/8r</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: E = v + Ir ------ (1) <br/> E = I(R + r) ------ (2) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<hr size=\"1\" />R+r</td></tr></table></div> <br/> Recall: <br/> P = I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>R <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">E<hr size=\"1\" />R+r</td><td style=\"text-align:center;\">)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">R</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />(R+r)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">R</td></tr></table></div> <br/> For maximum power transfer <br/> R = r <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />(r+r)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">r</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />(2r)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">r</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />4r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">r</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />4r</td></tr></table></div></div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2018 Model II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two strings each inclined at an angle of 30° to the horizontal are used to hold a bucket of water weighing 20N. Calculate the tension in each string.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span> N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20 N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span> N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 N</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">a<hr size=\"1\" />sinA</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">b<hr size=\"1\" />sinB</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20<hr size=\"1\" />sin60°</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">b<hr size=\"1\" />sin60°</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">b</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20×sin60<hr size=\"1\" />sin60</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20N</td></tr></table></div></div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2018 Model II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The resultant force in a couple is ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">infinite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the sum of the forces </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the product of the forces </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In physics, a couple is a system of forces with a resultant (a.k.a. net or sum) moment but no resultant force. Therefore, the resultant force in a couple is zero. Hence, the correct answer is zero.</div>", "topic": "EQUILIBRIUM OF FORCES"}, {"id": "objective>Physics>2018 Model II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a school compound, a girl walks 40m due east from the laboratory to the staff room to submit her report. Then she turns and walks 30m due north to her classroom. Determine the magnitude of her displacement from the laboratory.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">35m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">70m</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">R = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">40<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> + 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>&nbsp;</span> = 50m <br/>  <img src=\"2018 Model II/k38.png\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> ∴ the magnitude of her displacement from the laboratory is 50m.</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2018 Model II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The prolongation of sound wave after which the source has been withdrawn is called?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Absorption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Resonance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reverberation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Harmonic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The prolongation of sound wave after the source has been withdrawn is called Reverberation. This is a phenomenon that occurs when sound or signal is reflected causing a large number of reflections to build up and then decay as the sound is absorbed by the surfaces of objects in the space, which could include furniture, people, and air.</div>", "topic": "PROPAGATION OF SOUND WAVES : ECHO AND REVERBERATION"}, {"id": "objective>Physics>2018 Model II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A given mass of a gas occupies 120cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at s.t.p. Determine its volume at 273°C and 570mmHg.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">320cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">280cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">240cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">180cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = Standard temperature = 273K <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = Standard pressure = 760mmHg <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 120cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = unknown <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 273°C = 546K <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 570mmHg <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> {General gas equation} <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">760 × 120<hr size=\"1\" />273</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">570 × V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />546</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">760</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">120</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">570V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">4</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">40</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />2</td></tr></table></div> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 320cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2018 Model II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mouthpiece of a telephone primarily convert sound energy into</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mechanical</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrical</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chemical</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heat</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mouthpiece of a telephone primarily converts sound energy into electrical energy. This is done through a process called transduction, where a microphone in the mouthpiece captures the sound waves and converts them into electrical signals that can be transmitted over a distance.</div>", "topic": "MAGNETIC FIELD"}, {"id": "objective>Physics>2018 Model II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most suitable instrument for measuring the diameter of a thin wire accurately is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a metre rule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a pair of vernier callipers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a micrometer screw gauge </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a ruler </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since the wire is thin, a micrometer screw gauge which is capable of measurements to the nearest 0.001cm is most suitable.</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2018 Model II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The blurred images produced by a pin-hole camera with a very small hole is attributed to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reflection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polarization</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This effect is associated with diffraction, diffraction is the spreading of waves aftr passing through a through a tiny aperture </div>", "topic": "LIGHT ENERGY : PROPAGATION OF LIGHT"}, {"id": "objective>Physics>2018 Model II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> A bullet fired vertically upwards reaches a height of 500m. Neglecting air resistance, calculate the magnitude of the initial velocity of the bullet. [g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">500.0 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">100.0 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">70.0 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">50.0 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The initial velocity of the bullet can be calculated using the equation of motion: v^2 = u^2 + 2gs, where v is the final velocity, u is the initial velocity, g is the acceleration due to gravity, and s is the distance. Since the bullet is fired upwards and reaches a height of 500m, the final velocity (v) is 0. Substituting the given values into the equation gives: 0 = u^2 + 2*(-10)*500. Solving for u gives u = 100 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>.</div>", "topic": "MOTION: MOTION UNDER GRAVITY"}, {"id": "objective>Physics>2018 Model II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The volume of a bubble is doubled as it rises from the bottom to the top of a lake. If the atmospheric pressure is equivalent to 10.3m of water, the depth of the lake is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.15m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.3m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.6m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30.9m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The (air) bubble increases in size as it rises throuh the lake because of the decreasing pressure (PV) = constant). The pressure at the surface must be one -half of the pressure at the bottom of the lake. Hence, pressure at the bottom of the lake = 2 × 10.3 = 20.6m = atmospheric + 10.3m. <br/> This is the pressure at a depth of 10.3m of water.</div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2018 Model II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 20kg of water is allowed to cool from 75°C to 25°C. <br/> The quantity of heat loss is ...... <br/> [If S.H.C of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O = 4.2Jg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>°C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.2 KJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.2 MJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.2 GJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.2 TJ</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span> = 20kg = 20 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>g <br/> Δθ = 75°C - 25°C = 50°C <br/> Q = ?, c = 4.2 Jg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>°C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Recall: Q = mCΔθ ------ (1) <br/> Q = 20 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> × 4.2 × 50 <br/>  = 84 × 50 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  = 4200 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  = 4.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> <br/>  = 4.2 MJ</div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2018 Model II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Existence of land and sea breeze can be explained using ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Evaporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Conduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Convection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Radiation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The existence of land and sea breezes can be explained using convection. During the day, the land heats up faster than the sea, causing the air above the land to heat up and rise. This creates a low-pressure area over the land, and the cooler air over the sea moves in to replace it, creating a sea breeze. At night, the process is reversed, with the land cooling down faster than the sea, creating a land breeze. This cycle of heating, rising, cooling, and sinking is a type of convection.</div>", "topic": "HEAT TRANSFER : LAND AND SEA BREEZE"}, {"id": "objective>Physics>2018 Model II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A flask containing a volatile liquid at room temperature has the space above the liquid evacuated of all air and the valve closed. If the flask is now placed in a jar containing an ice-water mixture, the level of the liquid in the flask</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">remains the same</div>", "<div style=\"font-family:Cambria;font-size:17px;\">first increases and then decreases </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The space above the volatile liquid is filled with its vapour after the valve is closed. As the flask is placed in an ice-water mixture, the SVP of the liquid decreases, causing some vapour to condense and raise the level of liquid in the flask.</div>", "topic": "CHANGE OF STATE~~VAPOURS : UNSATURATED AND SATURATED VAPOURS"}, {"id": "objective>Physics>2018 Model II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The unit cycle per second is the same as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">watt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metres per second</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hertz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">radians per second</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The unit cycle per second is a unit of frequency. In the International System of Units (SI), the unit of frequency is the hertz (Hz). One hertz means one cycle per second. Therefore, the unit cycle per second is the same as hertz.</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2018 Model II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The law that explain the path of motion of the earth about the sun in an elliptical manner was stated by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kepler</div>", "<div style=\"font-family:Cambria;font-size:17px;\">faraday</div>", "<div style=\"font-family:Cambria;font-size:17px;\">galilei</div>", "<div style=\"font-family:Cambria;font-size:17px;\">newton</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The law that explains the path of motion of the earth about the sun in an elliptical manner was stated by Johannes Kepler. This is known as Kepler's First Law or the Law of Orbits, which states that all planets move in elliptical orbits, with the sun at one focus.</div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2018 Model II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A box of mass 100kg rests on a plane inclined at an angle of 30° to the horizontal. The coefficient of friction between the surface and the box is 0.2, If a force of 60N is applied parallel to the plane in an attempt to slide the box up the plane, the box will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">accelerate up the plane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">accelerate down the plane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">remain at rest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slide down the plane at a uniform speed</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The two forces acting down the plane are the resolved component of the box's weight = Wsin30° = 100sin30° <br/> = 50N, and  <br/> the limiting frictional force = μWcos30° <br/>  = 0.2(100)cos30° = 17.3N <br/>  <br/> The combined downward force (67.3N) is greater than the upward force, hence the box will accelerate down the plane.</div>", "topic": "FRICTION"}, {"id": "objective>Physics>2018 Model II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The wave property which can be used to confirm water to be a transverse wave is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">superposition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diffraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polarization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refraction</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Polarization is a property of waves that can oscillate with more than one orientation. In transverse waves, the direction of the oscillation is perpendicular to the direction of motion of the wave. Water waves are an example of transverse waves. Polarization can only occur in transverse waves, not in longitudinal waves where the direction of oscillation is the same as the direction of motion of the wave. Therefore, polarization can be used to confirm that water waves are transverse waves.</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2018 Model II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 2kW immersion heater is used to heat 1kg of water initially at a temperature of 20°C. How much water will boil away in 3 minutes? [specific heat capacity of water = 4.2 kJkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>°C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, specific latent heat of vaporization of water = 2.4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> kJkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">140g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">150g</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heat needed to raise the temperature of water from 20°C to 100°C = mcθ = 1(4.2)(80) = 336kJ <br/> Heat supplied by the 2kW heater in 3 minutes. <br/>  = 2(kJ/s) × 3 × 60(s) 360kJ <br/> The difference, 360 - 336 = 24kJ is used in boiling off m kg of water. <br/> Hence, 24 = mL<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">v</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">or</td><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">24<hr size=\"1\" />(2.4×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>kg</td><td style=\"text-align:center;\">or</td><td style=\"text-align:center;\">10g</td></tr></table></div></div>", "topic": "CHANGE OF STATE : SPECIFIC LATENT HEATS OF VAPORIZATION"}, {"id": "objective>Physics>2018 Model II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The slope of a straight-line velocity-time graph represents </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">uniform acceleration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">uniform speed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total distance travelled</div>", "<div style=\"font-family:Cambria;font-size:17px;\">work done</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It represents uniform acceleration. Recall acceleration is change in velocity over a period of time. <br/> </div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2018 Model II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The net vertical force in the diagram below is  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">42N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">44N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">36N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2018 Model II/b3gxp9.png\" style=\"position:relative;max-width:100%;\"/> <br/> Net vertical force, ∑F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> = (30cos45°)N + (20sin60°) + 25 - 20 = 43.53 = 44N</div>", "topic": "EQUILIBRIUM OF FORCES : EQUILIBRIUM OF PARTICLES"}, {"id": "objective>Physics>2018 Model II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The quality of a musical note depends on what?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">frequency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loudness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">harmonics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">echo</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The quality or timbre of a musical note is determined by its harmonics or overtones. These are frequencies that are multiples of the fundamental frequency of the note. They give the note its unique character, differentiating it from notes of the same pitch but produced by different instruments. Therefore, the correct answer is 'harmonics'.</div>", "topic": "CHARACTERISTICS OF SOUND WAVES : QUALITY, PITCH, INTENSITY AND LOUDNESS"}, {"id": "objective>Physics>2018 Model II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The prolongation of sound wave after which the source has been withdrawn is called?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Absorption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Resonance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reverberation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Harmonic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The prolongation of a sound wave after the source has been withdrawn is called reverberation. It is caused by the reflection of sound waves off surfaces, which causes the sound to be heard even after the source has stopped producing sound waves. Therefore, the correct answer is 'reverberation'.</div>", "topic": "PROPAGATION OF SOUND WAVES : ECHO AND REVERBERATION"}, {"id": "objective>Physics>2018 Model II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following dimensions represents impulse?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">MLT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">MLT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">MLT</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ML</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Impulse = Ft <br/> Force = ma <br/> a = v/t ; v = d/l = l/t <br/> a = LT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> so Force = MLT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> Therefore, Impulse = Ft  <br/>  = MLT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> × T = MLT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "MEASUREMENTS AND UNITS : DIMENSIONS"}, {"id": "objective>Physics>2018 Model II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the dimension of surface tension?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">MT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">ML<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Surface</td><td style=\"text-align:center;\">tension</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Force<hr size=\"1\" />Length</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Dimension</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">surface</td><td style=\"text-align:center;\">tension</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Dimension of force<hr size=\"1\" />Dimension of length</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Dimenison</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">surface</td><td style=\"text-align:center;\">tension</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">MLT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span><hr size=\"1\" />L</td></tr></table></div> <br/>  = MT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "topic": "MEASUREMENTS AND UNITS : DIMENSIONS"}, {"id": "objective>Physics>2018 Model II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is in a state of unstable equilibrium?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cone is in unstable equilibrium as a slight displacement will cause it to topple over and not return to its original position.</div>", "topic": "EQUILIBRIUM OF FORCES : CENTRE OF GRAVITY AND STABILITY"}, {"id": "objective>Physics>2018 Model II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two masses 2kg and 1.5kg are tied to the ends of a light inextensible to the ends of a light inextensible string which passes over a smooth light pulley which is fixed to the ceiling as shown in the diagram. The acceleration of the 2kg mass is (g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>) <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10.00 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.71 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.29 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.43 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Let T = tension in the string <br/> Applying Newton's second law to the 2kg mass; <br/> 20 - T = 2a ------ (i) <br/> and to the 1.5kg mass <br/> T - 15 = 1.5a ------ (ii) <br/> Adding (i) and (ii) gives <br/> 3.5a = 5  <br/>  a = 1.43 ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2018 Model II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The slope of a straight-line velocity-time graph represents </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">uniform acceleration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">uniform speed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total distance travelled</div>", "<div style=\"font-family:Cambria;font-size:17px;\">work done</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It represents uniform acceleration. Recall acceleration is change in velocity over a period of time. <br/> </div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2018 Model II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> From the velocity-time graph below, determine the total distance covered.  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">900 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">150 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">300 m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">450 m</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: <br/> the total distance S is the area under the graph. <br/> It should be noted that S is the area under the graph <br/> S = Area of Trapezium <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">S</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(15+30)×20<hr size=\"1\" />2</td></tr></table></div> <br/> S = 450 m</div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2018 Model II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is/are correct? <br/> I. Gravitational potential due to a mass at a point a distance r away is proportional to r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> II. Gravitational field strength is a scalar quantity <br/> III. Gravitational intensity is proportional to the weight of a unit mass</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and III </div>", "<div style=\"font-family:Cambria;font-size:17px;\">III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I only</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Gravitational</td><td style=\"text-align:center;\">potential,</td><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-GM<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span><hr size=\"1\" />r</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">(1)</td><td style=\"text-align:center;\">is</td><td style=\"text-align:center;\">wrong,</td><td style=\"text-align:center;\">V</td><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">1<hr size=\"1\" />r</td><td style=\"text-align:center;\">and</td><td style=\"text-align:center;\">not</td><td style=\"text-align:center;\">α</td><td style=\"text-align:center;\">1<hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> All strengths/intensities are vector quantities. So (II) is wrong only (III) is correct.</div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>2018 Model II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The escape velocity of an object from the gravitational field of a planet <br/> I. increases with the mass of the object <br/> II. increases with the mass of the planet <br/> III. is smaller on the moon than on the earth <br/> Which of the above statements is (are) correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Escape velocity, v = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"> 2Gm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span>/r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span>&nbsp;</span> = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2g<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span>r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span>&nbsp;</span>, <br/> where m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> and g<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> are the mass, radius of the planet and acceleration due to gravity on the planet respectively. Note that v is independent of the mass of the object. Also, since g<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> and r<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">p</span> are smaller for the moon, v is smaller on the moon.</div>", "topic": "GRAVITATIONAL FIELD : ESCAPE VELOCITY"}, {"id": "objective>Physics>2018 Model II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Diameter of a piece of wire <br/> II. Diameter of a piece of paper <br/> III. Diameter of a measuring cylinder <br/> IV. Length of a piece of wire <br/> Which of the above can be measured with a micrometer screw gauge.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III and IV only</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The micrometer screw gauge is useful in the measurement of the diameter of a piece of wire, thickness (diameter) of a piece of paper.</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}];
